let currentLang = localStorage.getItem('millionaire_lang') || 'az';
function applyCurrentLanguageAttributes(){
  try {
    document.documentElement.setAttribute('lang', currentLang || 'az');
    document.body.setAttribute('data-lang', currentLang || 'az');
  } catch(e) {}
}
applyCurrentLanguageAttributes();

function T(key) { return (I18N[currentLang] && I18N[currentLang][key]) || I18N.tr[key] || key; }
function activeBank() { return currentLang === 'tr' ? ORIGINAL_BANK : LANGUAGE_BANKS[currentLang]; }

const PRIZE_VALUES = [1000, 2000, 3000, 5000, 10000, 15000, 20000, 30000, 50000, 75000, 100000, 150000, 200000, 300000, 400000, 500000, 600000, 750000, 900000, 1000000];
const PRIZE_FORMATS = {
  az: { locale: "tr-TR", symbol: "₼", position: "after" },
  tr: { locale: "tr-TR", symbol: "₺", position: "after" },
  en: { locale: "en-US", symbol: "$", position: "before" },
  ru: { locale: "ru-RU", symbol: "₽", position: "after" }
};

function formatPrize(value) {
  const cfg = PRIZE_FORMATS[currentLang] || PRIZE_FORMATS.az;
  const number = Number(value || 0).toLocaleString(cfg.locale);
  return cfg.position === "before" ? `${cfg.symbol}${number}` : `${number} ${cfg.symbol}`;
}
function currentPrizes() { return PRIZE_VALUES.map(formatPrize); }
function prizeAt(index) { return formatPrize(PRIZE_VALUES[index] || 0); }
function finalPrize() { return prizeAt(PRIZE_VALUES.length - 1); }
function currentCurrencySymbol() {
  const cfg = PRIZE_FORMATS[currentLang] || PRIZE_FORMATS.az;
  return cfg.symbol;
}
function updateCurrencyLogos() {
  document.querySelectorAll(".splash-logo, .logo-orb").forEach(el => { el.textContent = currentCurrencySymbol(); });
}
const SAFE_LEVELS = new Set([4, 9, 14]);
const LETTERS = ["A", "B", "C", "D"];

let state = null;
let timer = null;

function byId(id) { return document.getElementById(id); }
function clone(obj) { return JSON.parse(JSON.stringify(obj)); }
function shuffle(arr) {
  const a = arr.slice();
  for(let i=a.length-1; i>0; i--) {
    const j = Math.floor(Math.random()*(i+1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}
function moneyNumber(label) {
  return Number(String(label).replace(/[^0-9]/g, "")) || 0;
}
function getBest() {
  return Number(localStorage.getItem("millionaire_best_score") || 0);
}
function setBest(value) {
  if(value > getBest()) localStorage.setItem("millionaire_best_score", String(value));
  updateStats();
}

function updateLanguageTopChip(){
  const chip = byId("langTopChip");
  if(chip) chip.textContent = (I18N[currentLang] && I18N[currentLang].short) || "TR";
  updateCurrencyLogos();
}

function updateStats() {
  const total = ORIGINAL_BANK.reduce((n,l)=>n+l.length,0);
  const bankStatEl = byId("bankStat"); if(bankStatEl) bankStatEl.textContent = "";
  const best = getBest();
  byId("bestStat").textContent = `${currentLang === 'ru' ? 'Рекорд:' : currentLang === 'en' ? 'Best:' : 'Rekor:'} ${formatPrize(best)}`;
}

function validateBank() {
  const errors = [];
  const seenQuestions = new Set();
  activeBank().forEach((level, li) => {
    if(!Array.isArray(level) || level.length < 1) errors.push(`Level ${li+1}: boş`);
    level.forEach((q, qi) => {
      const label = `Level ${li+1}, soru ${qi+1}`;
      if(!q.q || !Array.isArray(q.opts) || q.opts.length !== 4) errors.push(`${label}: format hatası`);
      if(Array.isArray(q.opts) && new Set(q.opts).size !== q.opts.length) errors.push(`${label}: tekrarlı seçenek`);
      if(!Number.isInteger(q.a) || q.a < 0 || q.a > 3) errors.push(`${label}: cevap index hatası`);
      const key = String(q.q || "").trim().toLowerCase().replace(/\s+/g, " ");
      if(seenQuestions.has(key)) errors.push(`${label}: tekrarlı soru`);
      seenQuestions.add(key);
    });
  });
  return errors;
}

function bankSummary() {
  const total = activeBank().reduce((n, level) => n + level.length, 0);
  const categoryCounts = {};
  activeBank().flat().forEach(q => {
    const c = q.category || categoryOf(q.q);
    categoryCounts[c] = (categoryCounts[c] || 0) + 1;
  });
  return { total, categoryCounts, levelCounts: activeBank().map(l => l.length), errors: validateBank() };
}

function categoryOf(text) {
  const t = text.toLowerCase();
  if(/azərbaycan|türkiye|ülke|paytaxt|başkent|nehir|dağ|okyanus|qitə|kıta/.test(t)) return "🌍 Coğrafya";
  if(/element|atom|dnt|dna|fizik|kimya|biyoloji|gezegen|güneş|planet|elektron/.test(t)) return "🔬 Bilim";
  if(/roman|yazarı|şair|eser|tablo|ressam/.test(t)) return "📚 Kültür";
  if(/savaş|devlet|imparator|yılda|tarix|cumhuriyet|osmanlı/.test(t)) return "🏛️ Tarih";
  if(/html|css|python|api|json|firebase|openai|cpu|ram|websocket|localstorage/.test(t)) return "💻 Teknoloji";
  return "🧠 Genel";
}

function normalizeQuestionText(text) {
  return String(text || "").toLowerCase().replace(/\s+/g, " ").trim();
}

function makeQuestionSet() {
  const usedCategories = [];
  const usedQuestions = new Set();
  return activeBank().map((level, idx) => {
    const pool = shuffle(level);
    const previousCategory = usedCategories[usedCategories.length - 1];
    let picked = pool.find(q => {
      const textKey = normalizeQuestionText(q.q);
      const category = q.category || categoryOf(q.q);
      return !usedQuestions.has(textKey) && category !== previousCategory;
    }) || pool.find(q => !usedQuestions.has(normalizeQuestionText(q.q))) || pool[0];
    const category = picked.category || categoryOf(picked.q);
    usedCategories.push(category);
    usedQuestions.add(normalizeQuestionText(picked.q));
    return { ...clone(picked), level: idx, category };
  });
}

function startGame() {
  clearInterval(timer);
  if(window.MillionaireAudio) window.MillionaireAudio.startBackground();
  showCountdownThen(() => {
    state = {
      level: 0,
      questions: makeQuestionSet(),
      selected: null,
      locked: false,
      revealed: false,
      hiddenOptions: new Set(),
      lifelines: { fifty:true, audience:true, phone:true },
      timeLeft: 30,
      info: ""
    };
    renderGame();
    startTimer();
  });
}

function startTimer() {
  clearInterval(timer);
  state.timeLeft = 30;
  timer = setInterval(() => {
    if(!state || state.locked) return;
    state.timeLeft -= 1;
    if(state.timeLeft <= 0) {
      clearInterval(timer);
      playGameAudio("wrong");
      stopGameAudio("countdown");
      finishGame(false, T("timeout"));
    } else {
      const el = byId("timer");
      if(el) {
        el.textContent = state.timeLeft;
        el.classList.toggle("urgent", state.timeLeft <= 7);
      }
      if(state.timeLeft === 10) playGameAudio("countdown");
      if(state.timeLeft > 10) stopGameAudio("countdown");
    }
  }, 1000);
}

function renderStart() {
  applyCurrentLanguageAttributes();
  document.body.classList.remove("game-active");
  updateLanguageTopChip();
  updateStats();
  renderPrizeDrawer();
  byId("app").innerHTML = `
    <div class="start start-premium">
      <div class="hero-badge">LIVE STAGE · ${currentLang.toUpperCase()}</div>
      <div class="logo-orb premium-logo">
        <span class="logo-currency">${currentCurrencySymbol()}</span>
        <span class="logo-ring"></span>
      </div>
      <div class="mini-stage"><span class="equalizer-bar"></span><span class="equalizer-bar"></span><span class="equalizer-bar"></span><span class="equalizer-bar"></span><span class="equalizer-bar"></span></div>
      <h2 class="hero-title">${T("startTitle")}</h2>
      <p class="hero-subtitle">${T("startText")} ${T("startSub")}</p>

      <div class="start-actions-panel">
        <div class="lang-section-title">${T("langTitle")}</div>
        <div class="lang-section-sub">${T("langSub")}</div>
        <div class="language-select" id="languageSelect">
          ${Object.entries(I18N).map(([code, lang]) => `
            <button class="lang-card ${currentLang === code ? "active" : ""}" data-lang="${code}">
              <span class="flag-dot">${code === 'az' ? '🇦🇿' : code === 'tr' ? '🇹🇷' : code === 'en' ? '🇬🇧' : '🇷🇺'}</span>
              <span>${lang.name}</span>
              <small>${lang.short}</small>
            </button>
          `).join("")}
        </div>
        <button class="btn primary-start" id="startBtn"><span>▶</span> ${T("newGame")}</button>
        <div class="start-settings-wrap">
          <button class="btn secondary icon-btn glass-btn" id="settingsBtn" aria-label="${modalText("settingsTitle")}" title="${modalText("settingsTitle")}">⚙️</button>
        </div>
      </div>
    </div>`;
}

function progressHtml() {
  return `<div class="progress">${currentPrizes().map((p,i)=>`
    <span class="step ${i < state.level ? "done" : ""} ${i === state.level ? "current" : ""} ${SAFE_LEVELS.has(i) ? "safe" : ""}">${i+1}</span>
  `).join("")}</div>`;
}

function renderGame() {
  applyCurrentLanguageAttributes();
  document.body.classList.add("game-active");
  updateLanguageTopChip();
  updateStats();
  const q = state.questions[state.level];
  const densityClass = questionDensityClass(q);
  byId("app").innerHTML = `
    <div class="game-shell">
      ${progressHtml()}
      <div class="topline premium-topline">
        <button class="btn secondary quit-premium" id="quitBtn">⏏ ${T('quit')}</button>
        <div class="timer timer-premium" id="timer"><span>${state.timeLeft}</span></div>
        <div class="money premium-money">
          <div class="label">${T('current')}</div>
          <div class="value">${prizeAt(state.level)}</div>
        </div>
      </div>
      <div class="question-box premium-question ${densityClass} ${state.locked && !state.revealed ? "locked-wait" : ""}">
        <div class="question-topline"><span>${T('question')} ${state.level+1}/20</span><span>${SAFE_LEVELS.has(state.level) ? '🛡️ ' + T('safe') : '🎯'}</span></div>
        <div class="question-text">${escapeHtml(q.q)}</div>
      </div>
      <div class="host-line premium-host">${hostLine()}</div>
      <div class="options premium-options ${densityClass} ${state.locked && !state.revealed ? "waiting-answer" : ""}">
        ${q.opts.map((opt, i) => optionHtml(opt, i)).join("")}
      </div>
      <div class="lifelines premium-lifelines">
        <button class="btn secondary lifeline ${!state.lifelines.fifty ? "used" : ""}" data-life="fifty" ${!state.lifelines.fifty || state.locked ? "disabled" : ""}><span class="life-icon">◐</span><b>50:50</b></button>
        <button class="btn secondary lifeline ${!state.lifelines.audience ? "used" : ""}" data-life="audience" ${!state.lifelines.audience || state.locked ? "disabled" : ""}><span class="life-icon">👥</span><b>${T('audience')}</b></button>
        <button class="btn secondary lifeline ${!state.lifelines.phone ? "used" : ""}" data-life="phone" ${!state.lifelines.phone || state.locked ? "disabled" : ""}><span class="life-icon">📞</span><b>${T('phone')}</b></button>
      </div>
      <div class="control-strip premium-control-strip">
        <button class="btn secondary sound-toggle mobile-prize-btn" id="prizeBtn">🏆 ${modalText("prizeTitle")}</button>
        <button class="btn secondary icon-btn glass-btn" id="settingsBtn" aria-label="${modalText("settingsTitle")}" title="${modalText("settingsTitle")}">⚙️</button>
      </div>
      <div class="info premium-info">${state.info || ""}</div>
    </div>
  `;
  renderPrizeDrawer();
}

function questionDensityClass(q) {
  if(!q) return "";
  const maxOpt = Math.max(...q.opts.map(o => String(o || "").length));
  const total = String(q.q || "").length + maxOpt;
  if(String(q.q || "").length > 125 || maxOpt > 58 || total > 175) return "dense-text";
  if(String(q.q || "").length > 92 || maxOpt > 44 || total > 130) return "compact-text";
  return "";
}

function optionHtml(opt, i) {
  const q = state.questions[state.level];
  let cls = "option premium-option";
  if(state.hiddenOptions.has(i)) cls += " hidden";
  if(state.selected === i && !state.revealed) cls += " selected";
  if(state.revealed && i === q.a) cls += " correct";
  if(state.revealed && state.selected === i && i !== q.a) cls += " wrong";
  return `<button class="${cls}" data-answer="${i}" aria-label="${LETTERS[i]}: ${escapeHtml(opt)}" ${state.locked || state.hiddenOptions.has(i) ? "disabled" : ""}>
    <span class="letter">${LETTERS[i]}</span>
    <span class="answer-text">${escapeHtml(opt)}</span>
    <span class="answer-shine"></span>
  </button>`;
}

function chooseAnswer(index) {
  if(!state || state.locked || state.hiddenOptions.has(index)) return;
  hapticTap([12]);
  // Cavab seçilən kimi birbaşa kilidlənir.
  // Əvvəlki "Son qərarın budur?" təsdiq pəncərəsi istifadəçi istəyinə əsasən deaktiv edildi.
  lockAnswer(index);
}

function lockAnswer(index) {
  if(!state || state.locked || state.hiddenOptions.has(index)) return;
  const q = state.questions[state.level];
  state.selected = index;
  state.locked = true;
  stopGameAudio("countdown");
  
  renderGame();

  // Cavab kilidləndikdən sonra qısa TV-show gözləmə effekti.
  setTimeout(() => {
    stopSuspensePulse();
    state.revealed = true;
    renderGame();

    if(index === q.a) {
      playGameAudio("correct");
      flashScreen("good");
      stagePulse("good");
      hapticTap([22, 35, 22]);
      state.info = T("correct");
      
      showResultLine(T("correctBig"), "good");
      showNextQuestionTransition();
      renderGame();
      setTimeout(nextLevel, 1050);
    } else {
      playGameAudio("wrong");
      flashScreen("bad");
      stagePulse("bad");
      hapticTap([60, 40, 60]);
      
      state.info = T("wrong");
      showResultLine(T("wrongBig"), "bad");
      renderGame();
      setTimeout(() => finishGame(false, T("wrong")), 1500);
    }
  }, answerRevealDelay());
}

function answerRevealDelay() {
  return state && state.level >= 14 ? 2800 : 2200;
}

function nextLevel() {
  if(state.level >= PRIZE_VALUES.length - 1) {
    finishGame(true, T("won"));
    return;
  }
  state.level += 1;
  state.selected = null;
  state.locked = false;
  state.revealed = false;
  state.hiddenOptions = new Set();
  state.info = "";
  playGameAudio("next");
  showCinematicStatus(T("next"), "gold");
  renderGame();
  startTimer();
}

function guaranteedMoney() {
  if(state.level > 14) return prizeAt(14);
  if(state.level > 9) return prizeAt(9);
  if(state.level > 4) return prizeAt(4);
  return formatPrize(0);
}

function finishGame(won, reason) {
  applyCurrentLanguageAttributes();
  document.body.classList.remove("game-active");
  stopSuspensePulse();
  stopGameAudio("countdown");
  clearInterval(timer);
  if(won) burstConfetti(140); else if(!lowFx) burstConfetti(22);
  const prizeLabel = won ? finalPrize() : guaranteedMoney();
  setBest(moneyNumber(prizeLabel));
  const resultTitle = won ? (currentLang === 'en' ? 'You are a Millionaire!' : currentLang === 'ru' ? 'Вы стали миллионером!' : currentLang === 'tr' ? 'Milyoner oldun!' : 'Sən Milyoner oldun!') : escapeHtml(reason);
  byId("app").innerHTML = `
    <div class="end premium-end ${won ? 'win' : 'lose'}">
      <div class="end-glow"></div>
      <div class="end-trophy">${won ? "🏆" : "🎭"}</div>
      <div class="end-kicker">${won ? T('won') : T('gameOver')}</div>
      <h2 class="end-title">${resultTitle}</h2>
      <div class="end-prize-card">
        <div class="end-label">${T('earned')}</div>
        <div class="big end-prize">${prizeLabel}</div>
      </div>
      <div class="pill gold end-record">${currentLang === 'ru' ? 'Рекорд:' : currentLang === 'en' ? 'Best:' : 'Rekor:'} ${formatPrize(getBest())}</div>
      <div class="end-actions">
        <button class="btn primary-start" id="startBtn"><span>↻</span> ${T("newGame")}</button>
        <button class="btn secondary icon-btn glass-btn" id="settingsBtn" aria-label="${modalText("settingsTitle")}">⚙️</button>
      </div>
      <div class="language-select compact-langs" id="languageSelect">
        ${Object.entries(I18N).map(([code, lang]) => `
          <button class="lang-card ${currentLang === code ? "active" : ""}" data-lang="${code}">
            <span class="flag-dot">${code === 'az' ? '🇦🇿' : code === 'tr' ? '🇹🇷' : code === 'en' ? '🇬🇧' : '🇷🇺'}</span>
            <span>${lang.short}</span>
          </button>
        `).join("")}
      </div>
    </div>`;
}

function useLifeline(type) {
  if(!state || state.locked || !state.lifelines[type]) return;
  const q = state.questions[state.level];
  state.lifelines[type] = false;

  if(type === "fifty") {
    showFiftyModalThen(() => {
      const wrong = [0,1,2,3].filter(i => i !== q.a);
      shuffle(wrong).slice(0,2).forEach(i => state.hiddenOptions.add(i));
      state.info = modalText("fiftySub");
      renderGame();
    });
    renderGame();
    return;
  }

  if(type === "audience") {
    const values = buildAudiencePrediction(q.a, state.level);
    state.info = modalText("audienceTitle");
    showAudienceModal(values);
    renderGame();
    return;
  }

  if(type === "phone") {
    state.info = modalText("phoneTitle");
    const suggested = phoneFriendSuggestion(q.a, state.level);
    showPhoneModal(LETTERS[suggested]);
    renderGame();
    return;
  }
}
function probabilityForLevel(level) {
  if(level < 5) return 0.92;
  if(level < 10) return 0.78;
  if(level < 15) return 0.66;
  return 0.56;
}

function phoneFriendSuggestion(correctIndex, level) {
  if(Math.random() < probabilityForLevel(level)) return correctIndex;
  return shuffle([0,1,2,3].filter(i => i !== correctIndex))[0];
}

function buildAudiencePrediction(correctIndex, level) {
  const values = [0,0,0,0];
  const confidence = probabilityForLevel(level);
  const audiencePicksCorrect = Math.random() < Math.max(0.55, confidence - 0.08);
  const leadingIndex = audiencePicksCorrect ? correctIndex : shuffle([0,1,2,3].filter(i => i !== correctIndex))[0];
  const lead = Math.floor((level < 5 ? 52 : level < 10 ? 44 : level < 15 ? 37 : 31) + Math.random()*14);
  values[leadingIndex] = lead;
  let rest = 100 - lead;
  const others = shuffle([0,1,2,3].filter(i => i !== leadingIndex));
  others.forEach((i, idx) => {
    if(idx === others.length - 1) values[i] = rest;
    else {
      const min = 5;
      const max = Math.max(min, rest - (others.length - idx - 1) * min);
      const v = min + Math.floor(Math.random() * (max - min + 1));
      values[i] = v;
      rest -= v;
    }
  });
  return values;
}

function hostLine() {
  if(!state) return "";
  if(state.locked && !state.revealed) return T("locked");
  if(state.revealed) return "";
  const lines = T("host");
  return lines[state.level % lines.length];
}

