function burstConfetti(amount = 34) {
  const icons = ["💸","✨","⭐","🟡","🏆"];
  for(let i=0;i<amount;i++){
    const el = document.createElement("div");
    el.className = "confetti-piece";
    el.textContent = icons[Math.floor(Math.random()*icons.length)];
    el.style.left = Math.random()*100 + "vw";
    el.style.setProperty("--confetti-x", ((Math.random()*120)-60) + "px");
    el.style.animationDuration = (1.8 + Math.random()*1.8) + "s";
    el.style.fontSize = (14 + Math.random()*18) + "px";
    document.body.appendChild(el);
    setTimeout(()=>el.remove(), 3800);
  }
}

const legacySoundOn = localStorage.getItem("millionaire_sound") !== "off";
let musicEnabled = localStorage.getItem("millionaire_music") === null ? legacySoundOn : localStorage.getItem("millionaire_music") !== "off";
let sfxEnabled = localStorage.getItem("millionaire_sfx") === null ? legacySoundOn : localStorage.getItem("millionaire_sfx") !== "off";
let lowFx = localStorage.getItem("millionaire_lowfx") === "on";
if(lowFx) document.body.classList.add("lowfx");

function saveAudioPrefs() {
  localStorage.setItem("millionaire_music", musicEnabled ? "on" : "off");
  localStorage.setItem("millionaire_sfx", sfxEnabled ? "on" : "off");
  localStorage.setItem("millionaire_sound", (musicEnabled || sfxEnabled) ? "on" : "off");
  if(window.MillionaireAudio) window.MillionaireAudio.applySoundState();
}

function toggleMusic() {
  musicEnabled = !musicEnabled;
  saveAudioPrefs();
  refreshSettingsModalIfOpen();
}

function toggleSfx() {
  sfxEnabled = !sfxEnabled;
  saveAudioPrefs();
  refreshSettingsModalIfOpen();
}

function toggleFx() {
  lowFx = !lowFx;
  localStorage.setItem("millionaire_lowfx", lowFx ? "on" : "off");
  document.body.classList.toggle("lowfx", lowFx);
  if(state) renderGame(); else renderStart();
  refreshSettingsModalIfOpen();
}

function renderPrizeDrawer() {
  const box = byId("prizeDrawer");
  if(!box) return;
  if(!state){
    box.innerHTML = "";
    return;
  }
  box.innerHTML = currentPrizes().map((p, i) => {
    let cls = "prize-row";
    if(SAFE_LEVELS.has(i)) cls += " safe";
    if(i < state.level) cls += " done";
    if(i === state.level) cls += " current";
    return `<div class="${cls}"><span>${i+1}</span><span>${p}</span></div>`;
  }).reverse().join("");
}

function escapeHtml(str) {
  return String(str).replace(/[&<>"']/g, ch => ({"&":"&amp;","<":"&lt;",">":"&gt;","\"":"&quot;","'":"&#039;"}[ch]));
}

function playGameAudio(name) {
  if(window.MillionaireAudio && typeof window.MillionaireAudio.play === "function") {
    window.MillionaireAudio.play(name);
  }
}

function stopGameAudio(name) {
  if(window.MillionaireAudio && typeof window.MillionaireAudio.stop === "function") {
    window.MillionaireAudio.stop(name);
  }
}

function playTone(name) {
  playGameAudio(name);
}

document.addEventListener("click", (e) => {
  const answer = e.target.closest("[data-answer]");
  if(answer) chooseAnswer(Number(answer.dataset.answer));

  const life = e.target.closest("[data-life]");
  if(life) useLifeline(life.dataset.life);

  if(e.target.id === "startBtn") startGame();
  if(e.target.id === "quitBtn") finishGame(false, T("gameOver"));
  if(e.target.id === "settingsBtn") showSettingsModal();
  const settingsAction = e.target.closest("[data-settings-action]");
  if(settingsAction){
    if(settingsAction.dataset.settingsAction === "music") toggleMusic();
    if(settingsAction.dataset.settingsAction === "sfx") toggleSfx();
    if(settingsAction.dataset.settingsAction === "fx") toggleFx();
  }
  if(e.target.id === "prizeBtn") showPrizeModal();
  if(e.target.closest("[data-close-modal]")) closeModal();
  const confirmAnswer = e.target.closest("[data-confirm-answer]");
  if(confirmAnswer) { const idx = Number(confirmAnswer.dataset.confirmAnswer); closeModal(); lockAnswer(idx); }
  if(e.target.closest("[data-close-prize]")) closeModal(".prize-modal-backdrop");
  if(e.target.closest("[data-close-settings]")) closeModal(".settings-modal-backdrop");
  if(e.target.classList.contains("settings-modal-backdrop")) closeModal(".settings-modal-backdrop");
  const langBtn = e.target.closest("[data-lang]");
  if(langBtn){ currentLang = langBtn.dataset.lang; localStorage.setItem("millionaire_lang", currentLang); renderStart(); refreshSettingsModalIfOpen(); }
});



