let deferredInstallPrompt = null;

window.addEventListener("load", () => {
  const splash = byId("mobileSplash");
  setTimeout(() => {
    if(splash) splash.classList.add("hide");
  }, 1150);
});

window.addEventListener("beforeinstallprompt", (e) => {
  e.preventDefault();
  deferredInstallPrompt = e;
  const dismissed = localStorage.getItem("install_prompt_dismissed") === "yes";
  if(!dismissed){
    setTimeout(() => {
      const prompt = byId("installPrompt");
      if(prompt) prompt.classList.add("show");
    }, 1800);
  }
});

function updateOfflineBadge(){
  const badge = byId("offlineBadge");
  if(!badge) return;
  badge.classList.toggle("show", !navigator.onLine);
}
window.addEventListener("online", updateOfflineBadge);
window.addEventListener("offline", updateOfflineBadge);
updateOfflineBadge();

if("serviceWorker" in navigator) {
  window.addEventListener("load", () => {
    navigator.serviceWorker.register("./sw.js").catch(() => {});
  });
}

document.addEventListener("click", async (e) => {
  if(e.target.id === "installDismiss"){
    localStorage.setItem("install_prompt_dismissed", "yes");
    const prompt = byId("installPrompt");
    if(prompt) prompt.classList.remove("show");
  }
  if(e.target.id === "installBtn"){
    const prompt = byId("installPrompt");
    if(deferredInstallPrompt){
      deferredInstallPrompt.prompt();
      await deferredInstallPrompt.userChoice.catch(()=>null);
      deferredInstallPrompt = null;
    }
    if(prompt) prompt.classList.remove("show");
  }
});

